package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.bind.JsonTreeWriter;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.lang.reflect.Type;

public class GsonToJsonTreeTest {

  private Gson gson;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
  }

  @Test
  public void toJsonTree_withNullSrc_returnsJsonNull() throws Exception {
    JsonElement result = gson.toJsonTree(null, Object.class);
    assertNotNull(result);
    assertTrue(result.isJsonNull());
  }

  @Test
  public void toJsonTree_withPrimitiveSrc_returnsJsonPrimitive() throws Exception {
    int src = 123;
    JsonElement result = gson.toJsonTree(src, Integer.class);
    assertNotNull(result);
    assertTrue(result.isJsonPrimitive());
    assertEquals(123, result.getAsInt());
  }

  @Test
  public void toJsonTree_withStringSrc_returnsJsonPrimitive() throws Exception {
    String src = "test";
    JsonElement result = gson.toJsonTree(src, String.class);
    assertNotNull(result);
    assertTrue(result.isJsonPrimitive());
    assertEquals("test", result.getAsString());
  }

  @Test
  public void toJsonTree_withObjectSrc_returnsJsonObject() throws Exception {
    TestClass src = new TestClass();
    src.a = 10;
    src.b = "hello";
    JsonElement result = gson.toJsonTree(src, TestClass.class);
    assertNotNull(result);
    assertTrue(result.isJsonObject());
    assertEquals(10, result.getAsJsonObject().get("a").getAsInt());
    assertEquals("hello", result.getAsJsonObject().get("b").getAsString());
  }

  @Test
  public void toJsonTree_invokesToJsonWithCorrectParameters() throws Exception {
    Gson spyGson = Mockito.spy(gson);
    JsonTreeWriter writer = new JsonTreeWriter();
    Object src = "spyTest";
    Type type = String.class;

    // Use reflection to invoke private toJson method to verify it is called by toJsonTree
    Method toJsonMethod = Gson.class.getDeclaredMethod("toJson", Object.class, Type.class, JsonWriter.class);
    toJsonMethod.setAccessible(true);

    // We spy on toJson to verify it is called
    doCallRealMethod().when(spyGson).toJson(any(), any(), any());

    JsonElement result = spyGson.toJsonTree(src, type);

    verify(spyGson, times(1)).toJson(eq(src), eq(type), any(JsonWriter.class));
    assertNotNull(result);
    assertTrue(result.isJsonPrimitive());
    assertEquals("spyTest", result.getAsString());
  }

  private static class TestClass {
    int a;
    String b;
  }
}
